function JobPostForm({ onJobCreated, setMessage }) {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    requiredSkills: '',
    company: '',
    location: '',
    type: 'Full-time',
    experienceLevel: 'Mid',
    salaryRange: ''
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const skills = typeof formData.requiredSkills === 'string' 
        ? formData.requiredSkills.split(',').map(s => s.trim()).filter(s => s)
        : formData.requiredSkills;

      const response = await axios.post('http://localhost:5000/api/jobs', {
        ...formData,
        requiredSkills: skills
      });

      if (response.data.success) {
        setMessage({ type: 'success', text: 'Job posted successfully!' });
        setFormData({ 
          title: '', description: '', requiredSkills: '', company: '', location: '',
          type: 'Full-time', experienceLevel: 'Mid', salaryRange: ''
        });    
        onJobCreated();
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Error posting job. Please try again.' });
    }
  };

  return (
    <form onSubmit={handleSubmit} className="job-post-form">
      <div className="form-group">
        <label>Job Title</label>
        <input
          type="text"
          value={formData.title}
          onChange={(e) => setFormData({...formData, title: e.target.value})}
          required
          placeholder="e.g. Senior Software Engineer"
        />
      </div>

      <div className="grid-2">
        <div className="form-group">
          <label>Company Name</label>
          <input
            type="text"
            value={formData.company}
            onChange={(e) => setFormData({...formData, company: e.target.value})}
            placeholder="e.g. TechCorp Inc."
          />
        </div>
        <div className="form-group">
          <label>Location</label>
          <input
            type="text"
            value={formData.location}
            onChange={(e) => setFormData({...formData, location: e.target.value})}
            placeholder="e.g. Remote, New York"
          />
        </div>
      </div>

      <div className="grid-3">
        <div className="form-group">
          <label>Job Type</label>
          <select 
            value={formData.type} 
            onChange={(e) => setFormData({...formData, type: e.target.value})}
          >
            <option value="Full-time">Full-time</option>
            <option value="Part-time">Part-time</option>
            <option value="Contract">Contract</option>
            <option value="Internship">Internship</option>
            <option value="Freelance">Freelance</option>
          </select>
        </div>
        <div className="form-group">
          <label>Experience</label>
          <select 
            value={formData.experienceLevel} 
            onChange={(e) => setFormData({...formData, experienceLevel: e.target.value})}
          >
            <option value="Entry">Entry Level</option>
            <option value="Mid">Mid Level</option>
            <option value="Senior">Senior Level</option>
            <option value="Lead">Lead / Manager</option>
          </select>
        </div>
        <div className="form-group">
          <label>Salary Range</label>
          <input
            type="text"
            value={formData.salaryRange}
            onChange={(e) => setFormData({...formData, salaryRange: e.target.value})}
            placeholder="e.g. $100k - $120k"
          />
        </div>
      </div>

      <div className="form-group">
        <label>Job Description</label>
        <textarea
          value={formData.description}
          onChange={(e) => setFormData({...formData, description: e.target.value})}
          required
          rows="6"
          placeholder="Describe the role, responsibilities, and perks..."
        />
      </div>

      <div className="form-group">
        <label>Required Skills (comma-separated)</label>
        <input
          type="text"
          value={formData.requiredSkills}
          onChange={(e) => setFormData({...formData, requiredSkills: e.target.value})}
          placeholder="e.g. React, Node.js, Python, AWS"
        />
      </div>

      <button type="submit" className="primary-btn">Create Job Listing</button>
    </form>
  );
}

function ResumeUploadForm({ jobs, setMessage }) {
  const [formData, setFormData] = useState({
    candidateName: '',
    email: '',
    phone: '',
    jobId: ''
  });
  const [file, setFile] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setMessage({ type: 'error', text: 'Please select a resume file (PDF or DOCX)' });
      return;
    }

    const uploadData = new FormData();
    uploadData.append('resume', file);
    Object.keys(formData).forEach(key => uploadData.append(key, formData[key]));

    try {
      const response = await axios.post('http://localhost:5000/api/resumes/upload', uploadData);       
      if (response.data.success) {
        setMessage({ type: 'success', text: 'Application submitted successfully!' });
        setFormData({ candidateName: '', email: '', phone: '', jobId: '' });
        setFile(null);
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Error uploading resume. Check file format.' });
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div className="form-group">
        <label>Select Job Position</label>
        <select
          value={formData.jobId}
          onChange={(e) => setFormData({...formData, jobId: e.target.value})}
          required
        >
          <option value="">-- Choose a position --</option>
          {jobs.map(job => (
            <option key={job._id} value={job._id}>
              {job.title} - {job.company || 'Company'}
            </option>
          ))}
        </select>
      </div>
      <div className="form-group">
        <label>Full Name</label>
        <input
          type="text"
          value={formData.candidateName}
          onChange={(e) => setFormData({...formData, candidateName: e.target.value})}
          required
          placeholder="Your full name"
        />
      </div>
      <div className="grid-2">
        <div className="form-group">
          <label>Email Address</label>
          <input
            type="email"
            value={formData.email}
            onChange={(e) => setFormData({...formData, email: e.target.value})}
            required
            placeholder="you@example.com"
          />
        </div>
        <div className="form-group">
          <label>Phone Number</label>
          <input
            type="tel"
            value={formData.phone}
            onChange={(e) => setFormData({...formData, phone: e.target.value})}
            placeholder="+1 (555) 000-0000"
          />
        </div>
      </div>
      <div className="form-group">
        <label>Upload Resume (PDF/DOCX)</label>
        <div style={{ 
          border: '2px dashed var(--border-color)', 
          padding: '24px', 
          borderRadius: '8px', 
          textAlign: 'center',
          background: 'var(--bg-color)'
        }}>
          <input
            type="file"
            accept=".pdf,.docx"
            onChange={(e) => setFile(e.target.files[0])}
            required
            style={{ border: 'none', background: 'transparent', padding: 0 }}
          />
          <p style={{marginTop: '8px', fontSize: '0.85rem', color: 'var(--text-tertiary)'}}>
            Maximum file size: 5MB
          </p>
        </div>
      </div>
      <button type="submit" className="primary-btn">Submit Application</button>
    </form>
  );
}

function Dashboard({ jobs }) {
  const [selectedJobId, setSelectedJobId] = useState('');
  const [rankings, setRankings] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const generateRankings = async () => {
    if (!selectedJobId) return;
    setLoading(true);
    setError('');
    try {
      const response = await axios.post(`http://localhost:5000/api/rankings/generate/${selectedJobId}`);
      if (response.data.success) {
        await fetchRankings();
      } else {
        setError(response.data.message || 'Failed to generate rankings');
      }
    } catch (error) {
      const errorMsg = error.response?.data?.message || error.message || 'Failed to generate rankings';
      setError(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  const fetchRankings = useCallback(async () => {
    if (!selectedJobId) return;
    try {
      const response = await axios.get(`http://localhost:5000/api/rankings/job/${selectedJobId}`);     
      if (response.data.success) {
        setRankings(response.data.data);
        setError('');
      }
    } catch (error) {
      setError('Failed to fetch rankings');
    }
  }, [selectedJobId]);

  useEffect(() => {
    if (selectedJobId) {
      fetchRankings();
      return;
    }
    setRankings([]);
    setError('');
  }, [selectedJobId, fetchRankings]);

  return (
    <div className="dashboard">
      <div className="form-group">
        <label>Select Job to Evaluate</label>
        <div className="inline-actions">
          <select 
            value={selectedJobId} 
            onChange={(e) => setSelectedJobId(e.target.value)}
            style={{ flex: 1 }}
          >
            <option value="">-- Choose a job position --</option>
            {jobs.map(job => (
              <option key={job._id} value={job._id}>{job.title}</option>
            ))}
          </select>
          <button 
            onClick={generateRankings} 
            disabled={!selectedJobId || loading}
            className="primary-btn"
            style={{ width: 'auto', padding: '14px 24px', whiteSpace: 'nowrap' }}
          >
            {loading ? 'Analyzing...' : 'Analyze Candidates'}
          </button>
        </div>
      </div>

      {error && (
        <div className="message error">
           {error}
        </div>
      )}

      {loading && (
        <div style={{textAlign: 'center', padding: '48px', color: 'var(--text-secondary)'}}>
          <div className="spinner" style={{fontSize: '2rem', marginBottom: '16px'}}>⏳</div>
          <p>Analyzing resumes against job requirements...</p>
        </div>
      )}

      {!loading && rankings.length === 0 && selectedJobId && !error && (
        <div style={{
          textAlign: 'center', 
          padding: '48px', 
          color: 'var(--text-tertiary)', 
          border: '2px dashed var(--border-color)', 
          borderRadius: '12px',
          background: 'var(--bg-color)'
        }}>
          <h3>No rankings generated yet</h3>
          <p>Click "Analyze Candidates" to run the AI matching algorithm.</p>
        </div>
      )}

      {rankings.length > 0 && (
        <div className="rankings-list" style={{ marginTop: '32px' }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center', 
            marginBottom: '16px',
            borderBottom: '1px solid var(--border-color)',
            paddingBottom: '16px'
          }}>
            <h3 style={{margin: 0}}>Top Candidates ({rankings.length})</h3>
            <span style={{fontSize: '0.9rem', color: 'var(--text-secondary)'}}>Sorted by Match Score</span>
          </div>

          {rankings.map((ranking, index) => {
             const score = ranking.matchPercentage || 0;
             const matchClass = score >= 75 ? 'high-match' : (score >= 50 ? 'med-match' : 'low-match');

             return (
              <div key={ranking._id} className="ranking-card">
                <div className={`rank-badge ${matchClass}`}>
                  {score.toFixed(0)}%
                </div>

                <div className="candidate-info" style={{ flex: 1 }}>
                  <h4>{ranking.resumeId?.candidateName || 'Unknown Candidate'}</h4>
                  <p>{ranking.resumeId?.email}</p>
                  <p style={{fontSize: '0.85rem', marginTop: '4px', opacity: 0.8}}>
                    {ranking.resumeId?.phone}
                  </p>
                </div>

                <div className="skills-section">
                  <div className="matched-label">Matched Skills</div>
                  <div className="matched-skills">
                    {ranking.matchedSkills?.length > 0 ? (
                      ranking.matchedSkills.slice(0, 4).join(', ') + 
                      (ranking.matchedSkills.length > 4 ? ` +${ranking.matchedSkills.length - 4}` : '')
                    ) : (
                      <span style={{color: 'var(--text-tertiary)'}}>No specific matches</span>
                    )}
                  </div>
                </div>

                <div style={{ textAlign: 'right' }}>
                   <div style={{ fontSize: '2rem', color: '#e3e8ee', fontWeight: 700 }}>#{index + 1}</div>
                </div>
              </div>
             );
          })}
        </div>
      )}
    </div>
  );
}

export default Home;
